class Integer {
    int value;
public:
    Integer(int val) : value(val) {}
    // Binary operator+ as member function
    int operator+(const Integer &i) {
        return value + i.value;  // this->value + i.value
    }
    // Overloaded: Integer + float
    int operator+(float nr) {
        return value + (int)nr;
    }
};

void main() {
    Integer n1(100), n2(200);
    int x = n1 + n2;     // calls n1.operator+(n2) => 300
    int y = n1 + 1.2f;   // calls n1.operator+(1.2f) => 101
}

class Integer {
    int value;
public:
    Integer(int val) : value(val) {}
    // Friend functions solve both directions
    friend int operator+(const Integer &i, float val);
    friend int operator+(float val, const Integer &i);
};

int operator+(const Integer &i, float val) {
    return i.value + (int)val;
}
int operator+(float val, const Integer &i) {
    return i.value + (int)val;
}

void main() {
    Integer n1(100), n2(200);
    int y = (1.2f + n1) + (n2 + 1.5f);  // Both directions work!
}

class Integer {
    int value;
public:
    Integer(int val) : value(val) {}

    // Relational -- returns bool (normal)
    bool operator>(const Integer &i) {
        return value > i.value;
    }

    // Unary -- no parameter as member function
    int operator!() {
        return 100 - this->value;  // custom meaning!
    }
};

void main() {
    Integer n1(20);
    int x = !n1;  // x = 80 (100 - 20)
}

class Integer {
    int value;
public:
    Integer(int val) : value(val) {}

    // Assignment -- returns reference for chaining
    Integer& operator=(int val) {
        value = val;
        return (*this);
    }

    // Prefix ++n1: increment then return reference
    Integer& operator++() {
        value += 1;
        return (*this);
    }

    // Postfix n1++: save old, increment, return old copy
    Integer operator++(int) {   // dummy int parameter
        Integer tempObject(value);  // Save old value
        value += 1;                 // Increment
        return (tempObject);        // Return OLD value
    }
};

