// Cast operator -- no return type needed
class Integer {
    int value;
public:
    Integer(int val) : value(val) {}
    operator float() {            // Cast to float
        return float(value * 2);
    }
};
void main() {
    Integer n1(2);
    float f1 = (float)n1;   // Explicit cast: f1 = 4.0
    float f2 = n1;           // Implicit conversion: f2 = 4.0
    float f3 = n1 + 0.2f;   // Cast applied first: f3 = 4.2
}

class Bool {
    bool value;
    const char * name;
public:
    Bool(bool val, const char * nm) : value(val), name(nm) {}
    Bool operator||(const Bool &i) {
        bool res = value || i.value;
        printf("Compute bool(%s || %s)=>%s\n", name, i.name,
               res ? "true" : "false");
        Bool b(res, "temp");
        return b;
    };
    operator bool() {
        printf("Return bool for %s => %s\n", name, value?"true":"false");
        return value;
    }
};

int main() {
    Bool n1(true,"n1"), n2(false,"n2"), n3(false,"n3");

    // With cast (built-in ||): lazy evaluation works
    bool res1 = ((bool)n1) || ((bool)n2) || ((bool)n3);
    // Output: "Return bool for n1 => true" (stops here!)

    // With overloaded ||: ALL evaluated
    bool res2 = n1 || n2 || n3;
    // Output: Compute(n1||n2)=>true, Compute(temp||n3)=>true, Return temp=>true
}

class Date {
    int X, Y, Z, T;
