// By value: copy constructor called to push 16 bytes onto stack
void Set(Date d, int value) { d.SetX(value); }

// By reference: only 4/8 byte address pushed
void Set(Date &d, int value) { d.SetX(value); }

void main() {
    Date d(1);
    Set(d, 123);  // Which overload? Depends on declaration
}

class String {
    char * text;
    void CopyString(const char * s) {
        text = new char[strlen(s) + 1];
        memcpy(text, s, strlen(s) + 1);
    }
public:
    String(const char * s) { CopyString(s); }
    ~String() { if (text) delete text; }

    // Copy constructor -- allocates NEW memory
    String(const String &obj) { CopyString(obj.text); }

    // Copy assignment -- frees old, allocates new
    String& operator=(const String &obj) {
        if (text) { delete text; text = nullptr; }
        CopyString(obj.text);
        return (*this);
    }

    // Move constructor -- STEALS the pointer
    String(String &&obj) {
        this->text = obj.text;
        obj.text = nullptr;   // Source loses ownership
    }

    // Move assignment -- STEALS the pointer
    String& operator=(String &&obj) {
        this->text = obj.text;
        obj.text = nullptr;
        return (*this);
    }
};
